# person.proto
# (Bu içeriği 'person.proto' adında bir dosyaya kaydedin)

# syntax = "proto3";
#
# message Person {
#   string name = 1;
#   int32 id = 2;
#   string email = 3;
#
#   enum PhoneType {
#     MOBILE = 0;
#     HOME = 1;
#     WORK = 2;
#   }
#
#   message PhoneNumber {
#     string number = 1;
#     PhoneType type = 2;
#   }
#
#   repeated PhoneNumber phones = 4;
# }

# Python kodu için ön hazırlık:
# 1. 'person.proto' dosyasını yukarıdaki içerikle oluşturun.
# 2. Terminalde şu komutu çalıştırarak Python sınıf dosyasını oluşturun:
#    protoc --python_out=. person.proto
# Bu komut 'person_pb2.py' adında bir dosya oluşturacaktır.
# 3. Aşağıdaki Python kodunu 'main.py' gibi bir dosyaya kaydedin ve çalıştırın.

import person_pb2

person = person_pb2.Person()
person.name = "Alice"
person.id = 1234
person.email = "alice@example.com"

phone1 = person.phones.add()
phone1.number = "555-1234"
phone1.type = person_pb2.Person.PhoneType.MOBILE

phone2 = person.phones.add()
phone2.number = "555-5678"
phone2.type = person_pb2.Person.PhoneType.HOME

serialized_data = person.SerializeToString()

new_person = person_pb2.Person()
new_person.ParseFromString(serialized_data)

print("Deserialized Person data:")
print(f"Name: {new_person.name}")
print(f"ID: {new_person.id}")
print(f"Email: {new_person.email}")

for phone in new_person.phones:
    print(f"  Phone Number: {phone.number}")
    print(f"  Phone Type: {person_pb2.Person.PhoneType.Name(phone.type)}")
